import { Component, EventKeyboard, Input, KeyCode, _decorator, error, input, log, Node, Sprite } from "cc";
import JP_Cell from "./JP_Cell";
import { tools } from "db://astarte-framework/utilis";
import { eventManager, newBottombarManager } from "db://astarte-framework/Managers";
import { JP_EVENT, JP_Type } from "./JP_Define";
import { JP_ShowAward } from "./JP_ShowAward";
import { BLACK_MASK_EVENT } from "../BlackMaskManager";
import { DEBUG } from "cc/env";
import { Common } from "../Common/Common";

const { ccclass, property } = _decorator;


@ccclass( "JP_Manager" )
export default class JP_Manager extends Component
{
    // ==================== 常數定義 ====================
    //#region 常數定義
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        JP_EVENT.INIT,
        JP_EVENT.CHANGE_BET,
        JP_EVENT.GET_JP_VALUE,
        JP_EVENT.PLAY_SHOW_AWARD,
        JP_EVENT.SHOW_BINGO_FRAME,
        JP_EVENT.HIDE_BINGO_FRAME,
        JP_EVENT.HIDE_ALL_BINGO_FRAME,
        JP_EVENT.SHOW_UI,
        JP_EVENT.HIDE_UI,
    ];

    /**
     * @ch 預設JP賠率配置（由小到大：MINI, MINOR, MAJOR, MEGA, GRAND）
     */
    private static readonly DEFAULT_JP_ODDS: number[] = [10, 15, 50, 250, 2500];

    //#endregion 常數定義

    // ==================== 屬性定義 ====================
    //#region 屬性定義
    /**@ch 根節點*/
    @property({
        type: Node,
        tooltip: "根節點"
    })
    private m_rootNode: Node = null;

    /**
     * @ch JP資訊顯示元件陣列，由小到大排列（MINI -> GRAND）
     */
    @property( {
        type: JP_Cell,
        tooltip: "JP資訊顯示元件陣列，由小到大排列（MINI -> GRAND）"
    } )
    private m_jpCells: JP_Cell[] = [];

    @property( {
        type: JP_ShowAward,
        tooltip: "播放大獎動畫元件"
    } )
    private m_jpShowAward: JP_ShowAward = null;

    @property({
        type: Sprite,
        tooltip: "Logo"
    })
    private m_logoSprite: Sprite = null;
    //#endregion 屬性定義

    //#region 變數
    /**
     * @ch JP賠率陣列
     */
    private m_jpOdds: number[] = JP_Manager.DEFAULT_JP_ODDS;

    /**
     * @ch 取得JP賠率（唯讀）
     */
    public get JpOdds() : Readonly<number[]>
    {
        return this.m_jpOdds;
    }

    /**
     * @ch JP實際金額值陣列
     */
    private m_jpValues: number[] = [];

    /**
     * @ch 初始化狀態標記
     */
    private m_isInit: boolean = false;

    /**
     * @ch 事件註冊狀態標記
     */
    private m_isEventRegistered: boolean = false;
    //#endregion 變數

    // ==================== 生命週期方法 ====================
    //#region 生命週期方法
    onLoad()
    {
        this.RegisterEvent();
        this.RegisterTestKeyCodes();
    }

    onDestroy()
    {
        this.UnregisterEvent();
        this.UnregisterTestKeyCodes();
    }
    //#endregion 生命週期方法

    // ==================== 事件管理 ====================
    //#region 事件管理

    /**
     * @ch 註冊事件監聽
     */
    private RegisterEvent(): void
    {
        if ( this.m_isEventRegistered )
        {
            return;
        }

        JP_Manager.EVENTS_TO_REGISTER.forEach( eventName =>
        {
            eventManager.Register( eventName, this );
        } );

        this.m_isEventRegistered = true;

        // 初始化中獎框為隱藏
        this.m_jpCells.forEach( cell => {
            cell.SetLightFrameShow(false);
        });
    }

    /**
     * @ch 取消註冊事件監聽
     */
    private UnregisterEvent(): void
    {
        if ( !this.m_isEventRegistered )
        {
            return;
        }

        JP_Manager.EVENTS_TO_REGISTER.forEach( eventName =>
        {
            eventManager.UnRegister( eventName, this );
        } );

        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件處理器
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent( event: string, ...args: any[] ): void
    {
        switch ( event )
        {
            case JP_EVENT.INIT:
                this.HandleInit( args[0] );
                break;

            case JP_EVENT.CHANGE_BET:
                this.HandleChangeBet( args[0] );
                break;

            case JP_EVENT.GET_JP_VALUE:
                this.HandleGetJPValue( args[0], args[1] );
                break;

            case JP_EVENT.PLAY_SHOW_AWARD:
                this.HandlePlayShowAward( args[0], args[1] );
                break;

            case JP_EVENT.SHOW_BINGO_FRAME:
                this.HandleShowBingoFrame( args[0] );
                break;

            case JP_EVENT.HIDE_BINGO_FRAME:
                this.HandleHideBingoFrame( args[0] );
                break;

            case JP_EVENT.HIDE_ALL_BINGO_FRAME:
                this.HandleHideAllBingoFrame();
                break;

            case JP_EVENT.SHOW_UI:
                this.SetUIShow( true );
                break;

            case JP_EVENT.HIDE_UI:
                this.SetUIShow( false );
                break;

            default:
                error( `JP_Manager: 未知的事件類型 "${event}"` );
                break;
        }
    }

    //#endregion 事件管理

    // ==================== 事件處理方法 ====================
    //#region 事件處理方法

    /**
     * @ch 處理初始化事件
     * @param odds JP賠率陣列
     */
    private HandleInit( odds: number[] ): void
    {
        this.Init( odds );
    }

    /**
     * @ch 處理投注變更事件
     * @param betValue 當前投注值
     */
    private HandleChangeBet( betValue: number ): void
    {
        this.OnChangeBet( betValue );
    }

    /**
     * @ch 處理取得JP值事件（透過回調返回）
     * @param jpType JP類型 （1=MINI, 2=MINOR, 3=MAJOR, 4=MEGA, 5=GRAND）
     * @param callback 回調函式
     */
    private HandleGetJPValue( jpType: number, callback?: ( value: number ) => void ): void
    {
        const value = this.GetJPValue( jpType );

        if ( typeof callback === "function" )
        {
            try
            {
                callback( value );
            }
            catch ( e )
            {
                error( `JP_Manager: 執行 GetJPValue 回調時發生錯誤: ${e}` );
            }
        }
    }

    /**
     * @ch 轉換JP類型
     * @param jpType JP類型 （1=MINI, 2=MINOR, 3=MAJOR, 4=MEGA, 5=GRAND）
     * @returns JP類型
     */
    private ConvertJPType( jpType: number ): JP_Type
    {
        switch ( jpType )
        {
            case 1: return JP_Type.MINI;
            case 2: return JP_Type.MINOR;
            case 3: return JP_Type.MAJOR;
            case 4: return JP_Type.MEGA;
            case 5: return JP_Type.GRAND;
            default:
                error( `JP_Manager: 轉換JP類型失敗 - 無效的JP類型 ${jpType}` );
                return JP_Type.MINI;
        }
    }

    /**
     * @ch 處理播放獲得JP的大獎動畫事件
     * @param jpType JP類型 （1=MINI, 2=MINOR, 3=MAJOR, 4=MEGA, 5=GRAND）
     * @param callback 完成回調
     */
    private HandlePlayShowAward( jpType: number, callback?: () => void ): void
    {
        this.PlayShowAward( jpType, callback );
    }

    /**
     * @ch 設置根節點顯示
     * @param isShow 是否顯示
     */
    private SetUIShow( isShow: boolean ): void
    {
        if ( !this.m_rootNode )
        {
            error( '[JP_Manager] m_rootNode is empty or null' );
            return;
        }
        this.m_rootNode.active = isShow;
    }
    //#endregion 事件處理方法

    // ==================== 初始化與更新 ====================
    //#region 初始化與更新
    /**
     * @ch 初始化JP系統
     * @param odds JP賠率陣列
     */
    private Init( odds: number[] ): void
    {
        // 參數驗證
        if ( !odds || odds.length === 0 )
        {
            error( "JP_Manager: 初始化失敗 - 賠率陣列不能為空" );
            return;
        }

        if ( odds.length !== this.m_jpCells.length )
        {
            error( `JP_Manager: 初始化失敗 - 賠率數量 (${odds.length}) 與顯示元件數量 (${this.m_jpCells.length}) 不符` );
            return;
        }

        // 初始化資料
        this.m_jpOdds = [...odds]; // 複製陣列避免外部修改
        this.m_jpValues = new Array( odds.length ).fill( 0 );
        this.m_isInit = true;

        // 刷新顯示
        this.RefreshJPDisplay();

        this.UpdateLogoSprite();
    }

    /**
     * @ch 更新JP賠率配置
     * @param odds 新的JP賠率陣列
     */
    private UpdateJP( odds: number[] ): void
    {
        if ( !this.m_isInit )
        {
            error( "JP_Manager: 更新失敗 - 系統尚未初始化，請先呼叫 Init" );
            return;
        }

        if ( !odds || odds.length === 0 )
        {
            error( "JP_Manager: 更新失敗 - 賠率陣列不能為空" );
            return;
        }

        if ( odds.length !== this.m_jpCells.length )
        {
            error( `JP_Manager: 更新失敗 - 賠率數量 (${odds.length}) 與顯示元件數量 (${this.m_jpCells.length}) 不符` );
            return;
        }

        this.m_jpOdds = [...odds];
        this.RefreshJPDisplay();
    }

    /**
     * @ch 刷新JP顯示
     */
    private RefreshJPDisplay(): void
    {
        if ( !this.m_isInit )
        {
            return;
        }

        const currentBet = newBottombarManager.GetNowBetValue();
        this.OnChangeBet( currentBet );
    }

    /**
     * @ch 更新Logo圖片
     */
    private UpdateLogoSprite()
    {
        const gameView = Common.GetGameView();
        if (this.m_logoSprite && gameView) {
            this.m_logoSprite.spriteFrame = gameView.LogoSprite;
        }
    }
    //#endregion 初始化與更新

    // ==================== JP計算與顯示 ====================
    //#region JP計算與顯示
    /**
     * @ch 處理投注變更，更新所有JP顯示
     * @param betValue 當前投注值
     */
    private OnChangeBet( betValue: number ): void
    {
        if ( !this.m_isInit )
        {
            return;
        }

        // 更新每個JP等級的顯示和實際值
        for ( let i = 0; i < this.m_jpOdds.length; i++ )
        {
            const jpValue = tools.times( betValue, this.m_jpOdds[ i ] );
            this.m_jpCells[ i ].SetJPShowValue( jpValue );
            this.m_jpValues[ i ] = jpValue;
        }
    }

    //#endregion JP計算與顯示

    // ==================== JP值查詢 ====================
    //#region JP值查詢
    /**
     * @ch 取得指定類型的JP實際金額值
     * @param jpType JP類型（1=MINI, 2=MINOR, 3=MAJOR, 4=MEGA, 5=GRAND）
     * @returns JP金額值，失敗時返回 0
     */
    private GetJPValue( jpType: number ): number
    {
        // 檢查初始化狀態
        if ( !this.m_isInit )
        {
            error( "JP_Manager: 取得JP值失敗 - 系統尚未初始化" );
            return 0;
        }

        // 檢查JP類型有效性
        if ( !this.IsValidJPType( jpType ) )
        {
            error( `JP_Manager: 取得JP值失敗 - 無效的JP類型 ${jpType}，有效範圍: ${JP_Type.MINI}-${JP_Type.MAX - 1}` );
            return 0;
        }

        return this.m_jpValues[ jpType - 1 ];
    }

    /**
     * @ch 檢查JP類型是否有效
     * @param jpType JP類型
     * @returns 是否為有效的JP類型
     */
    private IsValidJPType( jpType: number ): boolean
    {
        return Number.isInteger( jpType ) && jpType >= JP_Type.MINI && jpType < JP_Type.MAX && jpType <= this.m_jpValues.length;
    }
    //#endregion JP值查詢

    // ==================== JP動畫效果 ====================
    //#region JP動畫效果

    /**
     * @ch 播放獲得JP的大獎動畫
     * @param jpType JP類型 (1~5)
     * @param callback 動畫完成後的回調函式
     */
    private async PlayShowAward( jpType: number, callback?: () => void ): Promise<void>
    {
        // 顯示黑張
        eventManager.Dispatch( BLACK_MASK_EVENT.SHOW_BLACK_MASK );

        // 驗證JP類型
        if ( !this.IsValidJPType( jpType ) )
        {
            error( `JP_Manager: 播放大獎動畫失敗 - 無效的JP類型 ${jpType}` );
            callback?.();
            return;
        }

        if (!this.m_jpShowAward) {
            error( "JP_Manager: 播放大獎動畫元件不存在" );
            callback?.();
            return;
        }

        const jpValue = this.GetJPValue( jpType );
        const jpTypeEnum = this.ConvertJPType( jpType );
        log( `JP_Manager: 開始播放大獎動畫 (類型: ${jpTypeEnum}, 金額: ${jpValue})` );

        await this.m_jpShowAward.ShowAward(jpTypeEnum, jpValue);

        log( "JP_Manager: 播放大獎動畫完成" );

        // 隱藏黑張
        eventManager.Dispatch( BLACK_MASK_EVENT.HIDE_BLACK_MASK );

        // 執行完成回調
        callback?.();
    }

    /**
     * @ch 顯示中獎框
     * @param jpType JP類型
     */
    private HandleShowBingoFrame( jpType: number ): void
    {
        if ( !this.IsValidJPType( jpType ) )
        {
            error( `JP_Manager: 顯示中獎框失敗 - 無效的JP類型 ${jpType}` );
            return;
        }

        this.m_jpCells[ jpType - 1 ]?.PlayBingoFrameAnimation();
    }

    /**
     * @ch 隱藏中獎框
     * @param jpType JP類型
     */
    private HandleHideBingoFrame( jpType: number ): void
    {
        if ( !this.IsValidJPType( jpType ) )
        {
            error( `JP_Manager: 隱藏中獎框失敗 - 無效的JP類型 ${jpType}` );
            return;
        }

        this.m_jpCells[ jpType - 1 ]?.StopBingoFrameAnimation();
    }

    /**
     * @ch 隱藏所有中獎框
     */
    private HandleHideAllBingoFrame(): void
    {
        this.m_jpCells.forEach( cell => {
            cell.StopBingoFrameAnimation();
        });
    }
    //#endregion JP動畫效果

    //#region 測試功能
    /**
     * @ch 註冊測試按鍵
     */
    private RegisterTestKeyCodes() {
        if (!DEBUG) return;
        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 取消註冊測試按鍵
     */
    private UnregisterTestKeyCodes() {
        if (!DEBUG) return;
        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode(event: EventKeyboard) {
        return;
        log("CheckTestKeyCode", event.keyCode);
        switch (event.keyCode) {
            case KeyCode.DIGIT_1:
                // this.m_jpShowAward.ShowAward(JP_Type.GRAND, 1234567890.123);
                eventManager.Dispatch( JP_EVENT.SHOW_BINGO_FRAME, JP_Type.GRAND );
                break;

            case KeyCode.DIGIT_2:
                eventManager.Dispatch( JP_EVENT.HIDE_BINGO_FRAME, JP_Type.GRAND );
                break;
        }
    }
    //#endregion 測試功能
}

